#include <stdio.h>

int bankers_algorithm(int available[], int max[][3], int allocation[][3], int need[][3], int n) {
 int work[3];
 int finish[n];

 for (int i = 0; i < 3; i++) {
 work[i] = available[i];
 }

 for (int i = 0; i < n; i++) {
 finish[i] = 0;
 }

 while (1) {
 int i;
 for (i = 0; i < n; i++) {
 if (!finish[i] && need[i][0] <= work[0] && need[i][1] <= work[1] && need[i][2] <= work[2]) {
 work[0] += allocation[i][0];
 work[1] += allocation[i][1];
 work[2] += allocation[i][2];
 finish[i] = 1;
 break;
 }
 }

 if (i == n) {
 break;
 }
 }

 for (int i = 0; i < n; i++) {
 if (!finish[i]) {
 return 0;
 }
 }

 return 1;
}

int main() {
 int available[] = {3, 3, 2};
 int max[][3] = {{7, 5, 3}, {3, 2, 2}, {9, 0, 2}, {2, 2, 2}, {4, 3, 3}};
 int allocation[][3] = {{0, 1, 0}, {2, 0, 0}, {3, 0, 2}, {2, 1, 1}, {0, 0, 2}};
 int need[][3] = {{7, 4, 3}, {1, 2, 2}, {6, 0, 0}, {0, 1, 1}, {4, 3, 1}};

 printf("%d\n", bankers_algorithm(available, max, allocation, need, 5));
 return 0;
}
